#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MA=5e3+5,INF=0xfffffff;
int e[MA][MA],dis[MA][MA],n,m;
void init(){
    for(int i=1;i<=n;++i)
        for(int j=0;j<=n;++j)
            if(i==j)e[i][j]=dis[i][j]=0;
            else e[i][j]=dis[i][j]=INF;
}void Floyd(){
    int ans=INF;
    for(int k=1;k<=n;++k){
        for(int i=1;i<k;++i)
            for(int j=i+1;j<k;++j)
                ans=min(ans,dis[i][j]+e[i][k]+e[k][j]);
     	for(int i=1;i<=n;++i)
     	   for(int j=1;j<=n;++j)
     	       dis[i][j]=min(dis[i][j],dis[i][k]+dis[k][j]);
  	}if(ans==INF)printf("No solution.\n");
  	else printf("%d\n",ans);
}int main(void){
    scanf("%d%d",&n,&m);
    init();for(int i=1,a,b,c;i<=m;++i){
        scanf("%d%d%d",&a,&b,&c);if(c>e[a][b])continue;
        e[a][b]=e[b][a]=dis[a][b]=dis[b][a]=c;
    }Floyd();
    return false;
}
